import { Nitro } from '@nitrots/nitro-renderer';
import { IRoomEngine, RoomEngine, RoomObjectCategory, RoomObjectVariable } from '@nitrots/nitro-renderer/src/nitro/room';
import { Container } from '@pixi/display';
import { Graphics } from '@pixi/graphics';

export class TargetHighlightOverlay
{
    private _shape: Graphics | null = null;
    private _cachedUserId = 0;
    private _cachedObjectId = 0;
    private _cacheTtl = 0;

    public dispose(): void
    {
        if(this._shape)
        {
            this._shape.destroy(true);
            this._shape = null;
        }

        this._cachedUserId = 0;
        this._cachedObjectId = 0;
        this._cacheTtl = 0;
    }

    public update(engine: IRoomEngine): void
    {
        if(!engine)
        {
            this.hide();
            return;
        }

        const roomId = engine.activeRoomId;

        if(roomId < 0)
        {
            this.hide();
            return;
        }

        const canvasId = ((engine as any)._activeRoomActiveCanvas ?? 1);
        const canvas = engine.getRoomInstanceRenderingCanvas(roomId, canvasId);

        if(!canvas || !(canvas.master instanceof Container))
        {
            this.hide();
            return;
        }

        const master = (canvas.master as Container);
        const overlay = (master.getChildByName(RoomEngine.OVERLAY) as Container);

        if(!overlay)
        {
            this.hide();
            return;
        }

        const targetUserId = ((window as any).__rpTargetUserId ?? 0);

        if(targetUserId <= 0)
        {
            this.hide();
            return;
        }

        const objectId = this.resolveRoomObjectIdByUserId(engine, roomId, targetUserId);

        if(objectId < 0)
        {
            this.hide();
            return;
        }

        const rect = engine.getRoomObjectBoundingRectangle(roomId, objectId, RoomObjectCategory.UNIT, canvasId);

        if(!rect || rect.width <= 0 || rect.height <= 0)
        {
            this.hide();
            return;
        }

        if(!this._shape)
        {
            this._shape = new Graphics();
            this._shape.name = 'rp_target_outline';
            this._shape.interactive = false;
            (this._shape as any).eventMode = 'none';
            overlay.addChild(this._shape);
        }
        else if(this._shape.parent !== overlay)
        {
            overlay.addChild(this._shape);
        }

        const insetX = Math.max(8, Math.round(rect.width * 0.18));
        const insetTop = Math.max(2, Math.round(rect.height * 0.05));
        const insetBottom = Math.max(10, Math.round(rect.height * 0.12));

        const outlineX = Math.round(rect.x + insetX);
        const outlineY = Math.round(rect.y + insetTop);
        const outlineWidth = Math.max(20, Math.round(rect.width - (insetX * 2)));
        const outlineHeight = Math.max(32, Math.round(rect.height - insetTop - insetBottom));
        const radius = Math.max(10, Math.min(18, Math.round(outlineWidth * 0.28)));

        this._shape.clear();

        this._shape.beginFill(0xF4C542, 0.09);
        this._shape.drawRoundedRect(outlineX - 8, outlineY - 8, outlineWidth + 16, outlineHeight + 16, radius + 8);
        this._shape.endFill();

        this._shape.lineStyle(8, 0xF9E27D, 0.22);
        this._shape.drawRoundedRect(outlineX - 4, outlineY - 4, outlineWidth + 8, outlineHeight + 8, radius + 4);

        this._shape.lineStyle(4, 0xE0B13F, 0.95);
        this._shape.drawRoundedRect(outlineX, outlineY, outlineWidth, outlineHeight, radius);

        this._shape.lineStyle(2, 0xFFF4B8, 0.95);
        this._shape.drawRoundedRect(outlineX + 1, outlineY + 1, outlineWidth - 2, outlineHeight - 2, Math.max(8, radius - 2));

        this._shape.visible = true;
    }

    private hide(): void
    {
        if(this._shape) this._shape.visible = false;
    }

    private resolveRoomObjectIdByUserId(engine: IRoomEngine, roomId: number, userId: number): number
    {
        const now = performance.now();

        if(this._cachedUserId === userId && this._cachedObjectId >= 0 && now < this._cacheTtl)
        {
            return this._cachedObjectId;
        }

        try
        {
            const session = Nitro.instance.roomSessionManager.getSession(roomId) || Nitro.instance.roomSessionManager.getSession(-1);
            const roomIndex = session?.userDataManager?.getUserData?.(userId)?.roomIndex;

            if(typeof roomIndex === 'number' && roomIndex >= 0)
            {
                this._cachedUserId = userId;
                this._cachedObjectId = roomIndex;
                this._cacheTtl = now + 500;
                return roomIndex;
            }
        }
        catch {}

        const total = engine.getTotalObjectsForManager(roomId, RoomObjectCategory.UNIT);

        for(let i = 0; i < total; i++)
        {
            const obj = engine.getRoomObjectByIndex(roomId, i, RoomObjectCategory.UNIT);

            if(!obj?.model) continue;

            const directId = obj.model.getValue<number>(RoomObjectVariable.SESSION_CURRENT_USER_ID as any);

            if(typeof directId === 'number' && directId === userId)
            {
                this._cachedUserId = userId;
                this._cachedObjectId = obj.id;
                this._cacheTtl = now + 500;
                return obj.id;
            }
        }

        this._cachedUserId = userId;
        this._cachedObjectId = -1;
        this._cacheTtl = now + 250;

        return -1;
    }
}
